package com.fmcg.ecommerce.controller.admin; import com.fmcg.ecommerce.common.ApiResponse; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import org.springframework.http.ResponseEntity; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*; import java.util.HashMap; import java.util.Map; @RestController @RequestMapping("/api/v1/admin/settings") @Tag(name = "Admin Settings", description = "Admin settings and configurations APIs") public class AdminSettingsController { @GetMapping @PreAuthorize("hasRole('ADMIN')") @Operation(summary = "Get global store settings") public ResponseEntity<ApiResponse<Map<String, Object>>> getSettings() { Map<String, Object> settings = new HashMap<>(); settings.put("taxRate", 5.0); settings.put("shippingFee", 49.0); settings.put("currency", "INR"); return ResponseEntity.ok(ApiResponse.ok(settings)); } @PutMapping @PreAuthorize("hasRole('ADMIN')") @Operation(summary = "Update global store settings") public ResponseEntity<ApiResponse<Map<String, Object>>> updateSettings(@RequestBody Map<String, Object> request) { return ResponseEntity.ok(ApiResponse.ok("Settings updated", request)); } }
